const ctx = $input.first().json;
if (!ctx.results?.opportunities) throw new Error('Missing verified opportunities from Phase 5');
if (!ctx.results?.resume_profile) throw new Error('Missing resume_profile from Phase 3');

// Fan out jobs for ATS evaluation
return ctx.results.opportunities.map(job => ({
  json: { job, ctx }
}));

const jdData = $('Extract JD Intelligence').item.json;
const vectorRes = $input.first().json;

let vectorScore = null;

// If the OpenAI API succeeded and we have a mock resume vector in the DB, we would do Cosine Similarity.
// For n8n, doing cosine similarity in vanilla JS:
function cosineSim(vecA, vecB) {
    let dotProduct = 0, normA = 0, normB = 0;
    for (let i = 0; i < vecA.length; i++) {
        dotProduct += vecA[i] * vecB[i];
        normA += vecA[i] * vecA[i];
        normB += vecB[i] * vecB[i];
    }
    if (normA === 0 || normB === 0) return 0;
    return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
}

if (!vectorRes.error && vectorRes.data && vectorRes.data.length > 0) {
  const jdVector = vectorRes.data[0].embedding;
  // Normally we fetch resumeVector from Qdrant/DB here. 
  // Simulating a semantic match between 0.65 and 0.95 for demonstration if API succeeded.
  vectorScore = 0.65 + (Math.random() * 0.3);
}

return [{
  json: {
    ...jdData,
    ctx: $('Fan Out Jobs').item.json.ctx,
    vector_score: vectorScore
  }
}];

const allItems = $input.all();
const ctx = $('Fan Out Jobs').first().json.ctx;

const evaluatedJobs = allItems.map(item => item.json);

// Sort jobs by overall ATS score descending
evaluatedJobs.sort((a, b) => b.ats_evaluation.overall_score - a.ats_evaluation.overall_score);

// Update context
const newCtx = { ...ctx };
newCtx.results.opportunities = evaluatedJobs;
newCtx.agents_completed = [...(newCtx.agents_completed || []), 'ats_matching'];

return [{ json: { ctx: newCtx, jobsToInsert: evaluatedJobs } }];
